contracts/CreditScoreRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";

/**
 * @title CreditScoreRegistry
 * @notice Append-only on-chain credit score history per member wallet
 * @dev Only authorized ML_ORACLE_ROLE (backend) can write scores. Public read.
 *      Score range: 300–900 (uint16-safe). Each entry is timestamped.
 *      Used by LoanManager to query borrower creditworthiness.
 */
contract CreditScoreRegistry is AccessControl {
    bytes32 public constant ML_ORACLE_ROLE = keccak256("ML_ORACLE_ROLE");

    struct ScoreEntry {
        uint16 score;           // 300–900 scale
        string riskBand;        // "LOW" / "MEDIUM" / "HIGH"
        uint256 timestamp;
        bytes32 modelVersion;   // Hash of the ML model version
    }

    // member address → historical scores (append-only)
    mapping(address => ScoreEntry[]) private scoreHistory;

    // Latest score per member (quick lookup)
    mapping(address => ScoreEntry) public latestScore;

    // Track total entries for analytics
    uint256 public totalEntries;

    event ScoreRecorded(
        address indexed member,
        uint16 score,
        string riskBand,
        bytes32 modelVersion,
        uint256 timestamp
    );

    /**
     * @param _admin  Admin address (deployer)
     * @param _oracle ML oracle / backend address that writes scores
     */
    constructor(address _admin, address _oracle) {
        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
        _grantRole(ML_ORACLE_ROLE, _oracle);
    }

    /**
     * @notice Record a new credit score for a member
     * @param member      Wallet address of the SHG member
     * @param score       Credit score (300-900)
     * @param riskBand    "LOW", "MEDIUM", or "HIGH"
     * @param modelVer    Model version hash
     */
    function recordScore(
        address member,
        uint16 score,
        string calldata riskBand,
        bytes32 modelVer
    ) external onlyRole(ML_ORACLE_ROLE) {
        require(score >= 300 && score <= 900, "Score out of range");

        ScoreEntry memory entry = ScoreEntry({
            score: score,
            riskBand: riskBand,
            timestamp: block.timestamp,
            modelVersion: modelVer
        });

        scoreHistory[member].push(entry);
        latestScore[member] = entry;
        totalEntries++;

        emit ScoreRecorded(member, score, riskBand, modelVer, block.timestamp);
    }

    /**
     * @notice Get credit score history for a member
     */
    function getScoreHistory(address member)
        external
        view
        returns (ScoreEntry[] memory)
    {
        return scoreHistory[member];
    }

    /**
     * @notice Get number of score entries for a member
     */
    function getScoreCount(address member) external view returns (uint256) {
        return scoreHistory[member].length;
    }

    /**
     * @notice Get the latest score for a member (convenience)
     */
    function getLatestScore(address member) external view returns (uint16 score, string memory riskBand) {
        ScoreEntry storage entry = latestScore[member];
        return (entry.score, entry.riskBand);
    }
}

contracts/LoanManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";

/**
 * @title LoanManager
 * @notice Full loan lifecycle state machine — INR-native, no token transfers
 * @dev All amounts are INR in paise (₹25,000 = 2500000 paise).
 *      On-chain = immutable record. Off-chain = actual INR accounting via UPI/bank.
 *
 *      State machine:  PENDING → APPROVED → ACTIVE → REPAID | DEFAULTED
 *
 *      - PENDING:   Loan created by backend after SHG proposal
 *      - APPROVED:  Multi-sig quorum reached (SHGPool.executeLoan fired)
 *      - ACTIVE:    Backend marks disbursed after INR sent via UPI/bank
 *      - REPAID:    All EMIs marked as paid
 *      - DEFAULTED: EMI overdue > 30 day grace period
 *
 * @dev Roles:
 *      - BACKEND_ROLE: Backend wallet. Calls markDisbursed, markEmiPaid.
 *      - GROUP_LEADER_ROLE: SHG leaders. Calls approveLoan.
 *      - DEFAULT_ADMIN_ROLE: Deployer. Manages roles.
 */
contract LoanManager is ReentrancyGuard, AccessControl, Pausable {
    bytes32 public constant BACKEND_ROLE = keccak256("BACKEND_ROLE");
    bytes32 public constant GROUP_LEADER_ROLE = keccak256("GROUP_LEADER_ROLE");

    // ─── Loan State Machine ─────────────────────────────────────
    enum LoanStatus { PENDING, APPROVED, ACTIVE, REPAID, DEFAULTED }

    struct Loan {
        uint256 id;
        address borrower;
        bytes32 shgPoolId;              // Reference to SHGPool proposal
        uint256 principalPaise;         // ₹25,000 = 2500000
        uint256 interestRateBps;        // 1800 = 18% APR
        uint256 emiAmountPaise;         // Monthly EMI in paise
        uint256 tenureMonths;
        uint256 disbursedAt;            // Unix timestamp (0 if not yet disbursed)
        uint256 nextEmiDueAt;           // Unix timestamp of next EMI due date
        uint256 emisPaid;               // Number of EMIs paid
        LoanStatus status;
        bytes32 disbursalTxRef;         // Off-chain INR transaction reference
    }

    // ─── Storage ────────────────────────────────────────────────
    uint256 public loanCounter;
    mapping(uint256 => Loan) public loans;
    mapping(address => uint256[]) public borrowerLoans;

    // ─── Approval tracking per loan ─────────────────────────────
    mapping(uint256 => mapping(address => bool)) public loanApprovals;
    mapping(uint256 => uint256) public loanApprovalCount;
    uint256 public approvalQuorum;      // Required approvals for loan approval

    // ─── Constants ──────────────────────────────────────────────
    uint256 private constant SECONDS_PER_MONTH = 30 days;
    uint256 private constant DEFAULT_GRACE_PERIOD = 30 days;

    // ─── Events (immutable audit trail) ─────────────────────────
    event LoanCreated(
        uint256 indexed loanId,
        address indexed borrower,
        uint256 principalPaise,
        uint256 interestRateBps,
        uint256 tenureMonths,
        uint256 emiAmountPaise,
        uint256 timestamp
    );
    event LoanApprovedByLeader(
        uint256 indexed loanId,
        address indexed approver,
        uint256 approvalCount,
        uint256 timestamp
    );
    event LoanFullyApproved(
        uint256 indexed loanId,
        uint256 timestamp
    );
    event LoanDisbursed(
        uint256 indexed loanId,
        address indexed borrower,
        uint256 principalPaise,
        bytes32 txRef,
        uint256 timestamp
    );
    event EmiPaid(
        uint256 indexed loanId,
        uint256 emiNumber,
        uint256 emiAmountPaise,
        bytes32 upiRef,
        uint256 timestamp
    );
    event LoanRepaid(
        uint256 indexed loanId,
        address indexed borrower,
        uint256 timestamp
    );
    event LoanDefaulted(
        uint256 indexed loanId,
        address indexed borrower,
        uint256 overdueBy,
        uint256 timestamp
    );

    // ─── Errors ─────────────────────────────────────────────────
    error ZeroAmount();
    error ZeroTenure();
    error InvalidLoanStatus(uint256 loanId, LoanStatus expected, LoanStatus actual);
    error AlreadyApproved(uint256 loanId, address approver);
    error LoanNotOverdue(uint256 loanId);
    error AllEmisPaid(uint256 loanId);
    error LoanNotFound(uint256 loanId);

    /**
     * @param _backend       Backend wallet address
     * @param _approvalQuorum Number of group leader approvals required
     */
    constructor(address _backend, uint256 _approvalQuorum) {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(BACKEND_ROLE, _backend);
        approvalQuorum = _approvalQuorum;
    }

    // ─────────────────────────────────────────────────────────────
    // LOAN CREATION (Backend)
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Create a new loan record on-chain
     * @dev Called by backend after SHG proposal. Loan starts as PENDING.
     *      EMI = (principal / tenure) + (principal * rate / 10000 / 12)
     * @param borrower       Borrower wallet address
     * @param principalPaise Loan amount in INR paise
     * @param interestRateBps Annual interest rate in basis points (1800 = 18%)
     * @param tenureMonths   Loan tenure in months
     * @param shgPoolId      Reference to the SHGPool proposal ID
     * @return loanId        The newly created loan ID
     */
    function createLoan(
        address borrower,
        uint256 principalPaise,
        uint256 interestRateBps,
        uint256 tenureMonths,
        bytes32 shgPoolId
    ) external onlyRole(BACKEND_ROLE) whenNotPaused returns (uint256 loanId) {
        if (principalPaise == 0) revert ZeroAmount();
        if (tenureMonths == 0) revert ZeroTenure();

        loanId = ++loanCounter;

        // Calculate EMI: simple interest model
        // Monthly interest portion = (principal * rateBps) / (10000 * 12)
        // Monthly principal portion = principal / tenureMonths
        uint256 monthlyInterest = (principalPaise * interestRateBps) / (10000 * 12);
        uint256 principalPortion = principalPaise / tenureMonths;
        uint256 emiAmount = principalPortion + monthlyInterest;

        Loan storage loan = loans[loanId];
        loan.id = loanId;
        loan.borrower = borrower;
        loan.shgPoolId = shgPoolId;
        loan.principalPaise = principalPaise;
        loan.interestRateBps = interestRateBps;
        loan.emiAmountPaise = emiAmount;
        loan.tenureMonths = tenureMonths;
        loan.status = LoanStatus.PENDING;

        borrowerLoans[borrower].push(loanId);

        emit LoanCreated(
            loanId,
            borrower,
            principalPaise,
            interestRateBps,
            tenureMonths,
            emiAmount,
            block.timestamp
        );
    }

    // ─────────────────────────────────────────────────────────────
    // LOAN APPROVAL (Group Leaders)
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Group leader approves a pending loan
     * @dev When quorum is reached, status moves to APPROVED
     * @param loanId The loan to approve
     */
    function approveLoan(uint256 loanId) external onlyRole(GROUP_LEADER_ROLE) whenNotPaused {
        Loan storage loan = loans[loanId];
        if (loan.id == 0) revert LoanNotFound(loanId);
        if (loan.status != LoanStatus.PENDING) {
            revert InvalidLoanStatus(loanId, LoanStatus.PENDING, loan.status);
        }
        if (loanApprovals[loanId][msg.sender]) revert AlreadyApproved(loanId, msg.sender);

        loanApprovals[loanId][msg.sender] = true;
        loanApprovalCount[loanId]++;

        emit LoanApprovedByLeader(loanId, msg.sender, loanApprovalCount[loanId], block.timestamp);

        if (loanApprovalCount[loanId] >= approvalQuorum) {
            loan.status = LoanStatus.APPROVED;
            emit LoanFullyApproved(loanId, block.timestamp);
        }
    }

    // ─────────────────────────────────────────────────────────────
    // DISBURSEMENT MARKING (Backend)
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Mark loan as disbursed after INR has been sent off-chain
     * @dev Called by backend AFTER the INR disbursal via UPI/bank is confirmed.
     *      This is the on-chain immutable record of the disbursal event.
     *      No tokens move on-chain.
     * @param loanId The loan that was disbursed
     * @param txRef  Off-chain transaction reference (UPI ref / bank txn ID hash)
     */
    function markDisbursed(uint256 loanId, bytes32 txRef)
        external
        onlyRole(BACKEND_ROLE)
        whenNotPaused
    {
        Loan storage loan = loans[loanId];
        if (loan.id == 0) revert LoanNotFound(loanId);
        if (loan.status != LoanStatus.APPROVED) {
            revert InvalidLoanStatus(loanId, LoanStatus.APPROVED, loan.status);
        }

        loan.status = LoanStatus.ACTIVE;
        loan.disbursedAt = block.timestamp;
        loan.nextEmiDueAt = block.timestamp + SECONDS_PER_MONTH;
        loan.disbursalTxRef = txRef;

        emit LoanDisbursed(loanId, loan.borrower, loan.principalPaise, txRef, block.timestamp);
    }

    // ─────────────────────────────────────────────────────────────
    // EMI REPAYMENT RECORDING (Backend)
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Mark an EMI as paid after INR received via UPI/bank
     * @dev Called by backend AFTER the INR EMI payment is confirmed.
     *      No tokens move on-chain — this records the payment for the audit trail.
     *      When all EMIs are paid, loan status moves to REPAID.
     * @param loanId The loan being repaid
     * @param upiRef Off-chain UPI reference / bank transaction hash
     */
    function markEmiPaid(uint256 loanId, bytes32 upiRef)
        external
        onlyRole(BACKEND_ROLE)
        whenNotPaused
    {
        Loan storage loan = loans[loanId];
        if (loan.id == 0) revert LoanNotFound(loanId);
        if (loan.status != LoanStatus.ACTIVE) {
            revert InvalidLoanStatus(loanId, LoanStatus.ACTIVE, loan.status);
        }
        if (loan.emisPaid >= loan.tenureMonths) revert AllEmisPaid(loanId);

        loan.emisPaid++;
        loan.nextEmiDueAt = block.timestamp + SECONDS_PER_MONTH;

        emit EmiPaid(loanId, loan.emisPaid, loan.emiAmountPaise, upiRef, block.timestamp);

        // Check if all EMIs paid → mark REPAID
        if (loan.emisPaid >= loan.tenureMonths) {
            loan.status = LoanStatus.REPAID;
            emit LoanRepaid(loanId, loan.borrower, block.timestamp);
        }
    }

    // ─────────────────────────────────────────────────────────────
    // DEFAULT DETECTION
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Check if a loan has defaulted (EMI overdue > 30 day grace)
     * @dev Can be called by anyone (Chainlink Automation, backend cron, keeper).
     *      Only transitions ACTIVE loans with overdue EMIs past the grace period.
     * @param loanId The loan to check
     */
    function checkDefault(uint256 loanId) external {
        Loan storage loan = loans[loanId];
        if (loan.id == 0) revert LoanNotFound(loanId);
        if (loan.status != LoanStatus.ACTIVE) {
            revert InvalidLoanStatus(loanId, LoanStatus.ACTIVE, loan.status);
        }

        uint256 overdueThreshold = loan.nextEmiDueAt + DEFAULT_GRACE_PERIOD;
        if (block.timestamp <= overdueThreshold) revert LoanNotOverdue(loanId);

        uint256 overdueBy = block.timestamp - loan.nextEmiDueAt;
        loan.status = LoanStatus.DEFAULTED;

        emit LoanDefaulted(loanId, loan.borrower, overdueBy, block.timestamp);
    }

    // ─────────────────────────────────────────────────────────────
    // VIEW FUNCTIONS
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Get all loan IDs for a borrower
     */
    function getBorrowerLoans(address borrower) external view returns (uint256[] memory) {
        return borrowerLoans[borrower];
    }

    /**
     * @notice Get full loan details
     */
    function getLoan(uint256 loanId) external view returns (
        address borrower,
        bytes32 shgPoolId,
        uint256 principalPaise,
        uint256 interestRateBps,
        uint256 emiAmountPaise,
        uint256 tenureMonths,
        uint256 disbursedAt,
        uint256 nextEmiDueAt,
        uint256 emisPaid,
        LoanStatus status,
        bytes32 disbursalTxRef
    ) {
        Loan storage loan = loans[loanId];
        return (
            loan.borrower,
            loan.shgPoolId,
            loan.principalPaise,
            loan.interestRateBps,
            loan.emiAmountPaise,
            loan.tenureMonths,
            loan.disbursedAt,
            loan.nextEmiDueAt,
            loan.emisPaid,
            loan.status,
            loan.disbursalTxRef
        );
    }

    /**
     * @notice Get the total number of loans created
     */
    function totalLoans() external view returns (uint256) {
        return loanCounter;
    }

    // ─── Role Management ────────────────────────────────────────

    /**
     * @notice Grant GROUP_LEADER_ROLE to an address
     */
    function addGroupLeader(address leader) external onlyRole(DEFAULT_ADMIN_ROLE) {
        _grantRole(GROUP_LEADER_ROLE, leader);
    }

    /**
     * @notice Revoke GROUP_LEADER_ROLE from an address
     */
    function removeGroupLeader(address leader) external onlyRole(DEFAULT_ADMIN_ROLE) {
        _revokeRole(GROUP_LEADER_ROLE, leader);
    }

    /**
     * @notice Update the approval quorum
     */
    function setApprovalQuorum(uint256 newQuorum) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(newQuorum > 0, "Quorum must be > 0");
        approvalQuorum = newQuorum;
    }

    // ─── Pause controls ─────────────────────────────────────────
    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) { _pause(); }
    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) { _unpause(); }
}

contracts/SHGPool.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";

/**
 * @title SHGPool
 * @notice Multi-signature group wallet for Self-Help Groups (SHGs) — INR-native
 * @dev No ERC-20 tokens. All amounts are INR in paise (₹25,000 = 2500000 paise).
 *      On-chain = immutable audit trail via events. Off-chain = actual INR accounting.
 *      M-of-N approval required for loan proposals. Backend calls executeLoan
 *      after confirming INR has been disbursed off-chain (double-auth).
 */
contract SHGPool is ReentrancyGuard, AccessControl, Pausable {
    bytes32 public constant LEADER_ROLE = keccak256("LEADER_ROLE");
    bytes32 public constant BACKEND_ROLE = keccak256("BACKEND_ROLE");

    // ─── Pool Identity ──────────────────────────────────────────
    string public shgName;
    uint256 public quorumThreshold;
    address[] public members;
    uint256 public memberCount;

    // ─── Proposal State ─────────────────────────────────────────
    enum ProposalStatus { PENDING, QUORUM_REACHED, EXECUTED, CANCELLED }

    struct Proposal {
        address borrower;
        uint256 amountPaise;        // INR in paise (e.g., 2500000 = ₹25,000)
        uint256 tenureMonths;
        uint256 approvalCount;
        ProposalStatus status;
        uint256 createdAt;
        mapping(address => bool) hasApproved;
    }

    mapping(bytes32 => Proposal) private proposals;
    bytes32[] public proposalIds;

    // ─── Proposal View (for external reads) ────────────────────
    struct ProposalView {
        bytes32 proposalId;
        address borrower;
        uint256 amountPaise;
        uint256 tenureMonths;
        uint256 approvalCount;
        ProposalStatus status;
        uint256 createdAt;
    }

    // ─── Events (audit trail — backend reconciles against these) ─
    event MemberAdded(address indexed member, uint256 timestamp);
    event MemberRemoved(address indexed member, uint256 timestamp);
    event LoanProposed(
        bytes32 indexed proposalId,
        address indexed borrower,
        uint256 amountPaise,
        uint256 tenureMonths,
        uint256 timestamp
    );
    event LoanApproved(
        bytes32 indexed proposalId,
        address indexed approver,
        uint256 approvalCount,
        uint256 timestamp
    );
    event QuorumReached(bytes32 indexed proposalId, uint256 timestamp);
    event LoanExecuted(
        bytes32 indexed proposalId,
        address indexed borrower,
        uint256 amountPaise,
        uint256 timestamp
    );
    event ProposalCancelled(bytes32 indexed proposalId, uint256 timestamp);

    // ─── Errors ─────────────────────────────────────────────────
    error InvalidQuorum(uint256 quorum, uint256 memberCount);
    error ZeroAmount();
    error ZeroTenure();
    error ProposalNotActive(bytes32 proposalId);
    error AlreadyApproved(bytes32 proposalId, address approver);
    error QuorumNotReached(bytes32 proposalId);
    error AlreadyMember(address member);
    error NotMember(address member);

    /**
     * @param _members Initial SHG member addresses (first member gets ADMIN)
     * @param _quorum  Number of approvals required (e.g., 3 of 5)
     * @param _name    SHG group name
     * @param _backend Backend wallet address for executeLoan
     */
    constructor(
        address[] memory _members,
        uint256 _quorum,
        string memory _name,
        address _backend
    ) {
        if (_members.length < _quorum || _quorum == 0) {
            revert InvalidQuorum(_quorum, _members.length);
        }

        shgName = _name;
        quorumThreshold = _quorum;

        _grantRole(DEFAULT_ADMIN_ROLE, _members[0]);
        _grantRole(BACKEND_ROLE, _backend);

        for (uint256 i = 0; i < _members.length; i++) {
            _grantRole(LEADER_ROLE, _members[i]);
            members.push(_members[i]);
            emit MemberAdded(_members[i], block.timestamp);
        }
        memberCount = _members.length;
    }

    // ─────────────────────────────────────────────────────────────
    // LOAN PROPOSAL LIFECYCLE
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Propose a loan for a borrower (leaders only)
     * @param borrower  Borrower wallet address
     * @param amountPaise Loan amount in INR paise (e.g., 2500000 = ₹25,000)
     * @param tenureMonths Loan tenure in months
     * @return proposalId Unique proposal identifier
     */
    function proposeLoan(
        address borrower,
        uint256 amountPaise,
        uint256 tenureMonths
    )
        external
        onlyRole(LEADER_ROLE)
        whenNotPaused
        returns (bytes32 proposalId)
    {
        if (amountPaise == 0) revert ZeroAmount();
        if (tenureMonths == 0) revert ZeroTenure();

        proposalId = keccak256(
            abi.encodePacked(borrower, amountPaise, tenureMonths, block.timestamp, msg.sender)
        );

        Proposal storage p = proposals[proposalId];
        p.borrower = borrower;
        p.amountPaise = amountPaise;
        p.tenureMonths = tenureMonths;
        p.status = ProposalStatus.PENDING;
        p.createdAt = block.timestamp;
        proposalIds.push(proposalId);

        emit LoanProposed(proposalId, borrower, amountPaise, tenureMonths, block.timestamp);
    }

    /**
     * @notice Approve a pending loan proposal (leaders only, one vote per leader)
     * @param proposalId The proposal to approve
     */
    function approveLoan(bytes32 proposalId) external onlyRole(LEADER_ROLE) whenNotPaused {
        Proposal storage p = proposals[proposalId];
        if (p.status != ProposalStatus.PENDING) revert ProposalNotActive(proposalId);
        if (p.hasApproved[msg.sender]) revert AlreadyApproved(proposalId, msg.sender);

        p.hasApproved[msg.sender] = true;
        p.approvalCount++;

        emit LoanApproved(proposalId, msg.sender, p.approvalCount, block.timestamp);

        if (p.approvalCount >= quorumThreshold) {
            p.status = ProposalStatus.QUORUM_REACHED;
            emit QuorumReached(proposalId, block.timestamp);
        }
    }

    /**
     * @notice Execute a proposal after quorum reached AND backend confirms INR disbursement
     * @dev Double-auth: on-chain quorum + off-chain INR disbursement trigger.
     *      Backend calls this AFTER the INR has been sent to borrower via UPI/bank.
     *      No tokens move on-chain — this is purely an immutable record.
     * @param proposalId The approved proposal to execute
     */
    function executeLoan(bytes32 proposalId) external onlyRole(BACKEND_ROLE) whenNotPaused {
        Proposal storage p = proposals[proposalId];
        if (p.status != ProposalStatus.QUORUM_REACHED) revert QuorumNotReached(proposalId);

        p.status = ProposalStatus.EXECUTED;

        emit LoanExecuted(proposalId, p.borrower, p.amountPaise, block.timestamp);
    }

    /**
     * @notice Cancel a pending proposal (admin only)
     * @param proposalId The proposal to cancel
     */
    function cancelProposal(bytes32 proposalId) external onlyRole(DEFAULT_ADMIN_ROLE) {
        Proposal storage p = proposals[proposalId];
        if (p.status != ProposalStatus.PENDING && p.status != ProposalStatus.QUORUM_REACHED) {
            revert ProposalNotActive(proposalId);
        }
        p.status = ProposalStatus.CANCELLED;
        emit ProposalCancelled(proposalId, block.timestamp);
    }

    // ─────────────────────────────────────────────────────────────
    // MEMBER MANAGEMENT
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Add a new member to the SHG (admin only)
     */
    function addMember(address member) external onlyRole(DEFAULT_ADMIN_ROLE) {
        if (hasRole(LEADER_ROLE, member)) revert AlreadyMember(member);
        _grantRole(LEADER_ROLE, member);
        members.push(member);
        memberCount++;
        emit MemberAdded(member, block.timestamp);
    }

    /**
     * @notice Remove a member from the SHG (admin only)
     * @dev Does not compact the members array (gas optimization)
     */
    function removeMember(address member) external onlyRole(DEFAULT_ADMIN_ROLE) {
        if (!hasRole(LEADER_ROLE, member)) revert NotMember(member);
        _revokeRole(LEADER_ROLE, member);
        memberCount--;
        emit MemberRemoved(member, block.timestamp);
    }

    // ─────────────────────────────────────────────────────────────
    // VIEW FUNCTIONS
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Get proposal details (without the approval mapping)
     */
    function getProposal(bytes32 proposalId) external view returns (ProposalView memory) {
        Proposal storage p = proposals[proposalId];
        return ProposalView({
            proposalId: proposalId,
            borrower: p.borrower,
            amountPaise: p.amountPaise,
            tenureMonths: p.tenureMonths,
            approvalCount: p.approvalCount,
            status: p.status,
            createdAt: p.createdAt
        });
    }

    /**
     * @notice Check if a specific leader has approved a proposal
     */
    function hasApproved(bytes32 proposalId, address leader) external view returns (bool) {
        return proposals[proposalId].hasApproved[leader];
    }

    /**
     * @notice Total number of proposals
     */
    function proposalCount() external view returns (uint256) {
        return proposalIds.length;
    }

    /**
     * @notice Get all member addresses
     */
    function getMembers() external view returns (address[] memory) {
        return members;
    }

    // ─── Pause controls ─────────────────────────────────────────
    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) { _pause(); }
    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) { _unpause(); }
}

contracts/SHGPoolFactory.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "./SHGPool.sol";

/**
 * @title SHGPoolFactory
 * @notice Factory contract to deploy new SHGPool instances
 * @dev Creates deterministic SHGPool addresses. Maintains a registry of all deployed pools.
 *      Backend calls createPool() when a new SHG group is formed off-chain.
 */
contract SHGPoolFactory is AccessControl {
    bytes32 public constant BACKEND_ROLE = keccak256("BACKEND_ROLE");

    // ─── Registry ───────────────────────────────────────────────
    address[] public deployedPools;
    mapping(address => bool) public isPool;
    mapping(string => address) public poolByName;  // SHG name → pool address

    address public loanManagerAddress;
    address public backendWallet;

    // ─── Events ─────────────────────────────────────────────────
    event PoolCreated(
        address indexed poolAddress,
        string shgName,
        uint256 quorum,
        uint256 memberCount,
        uint256 timestamp
    );

    /**
     * @param _loanManager   Address of the LoanManager contract
     * @param _backendWallet Backend wallet address (gets BACKEND_ROLE on each pool)
     */
    constructor(address _loanManager, address _backendWallet) {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(BACKEND_ROLE, _backendWallet);
        loanManagerAddress = _loanManager;
        backendWallet = _backendWallet;
    }

    /**
     * @notice Deploy a new SHGPool contract for a Self-Help Group
     * @param members  Array of member wallet addresses
     * @param quorum   Number of approvals needed (M-of-N)
     * @param name     SHG group name
     * @return pool    Address of the deployed SHGPool
     */
    function createPool(
        address[] calldata members,
        uint256 quorum,
        string calldata name
    ) external onlyRole(BACKEND_ROLE) returns (address pool) {
        require(bytes(name).length > 0, "Name required");
        require(poolByName[name] == address(0), "Pool name already exists");

        SHGPool newPool = new SHGPool(members, quorum, name, backendWallet);
        pool = address(newPool);

        deployedPools.push(pool);
        isPool[pool] = true;
        poolByName[name] = pool;

        emit PoolCreated(pool, name, quorum, members.length, block.timestamp);
    }

    /**
     * @notice Get total number of deployed pools
     */
    function poolCount() external view returns (uint256) {
        return deployedPools.length;
    }

    /**
     * @notice Get all deployed pool addresses
     */
    function getAllPools() external view returns (address[] memory) {
        return deployedPools;
    }

    /**
     * @notice Update the LoanManager address (admin only)
     */
    function setLoanManager(address _loanManager) external onlyRole(DEFAULT_ADMIN_ROLE) {
        loanManagerAddress = _loanManager;
    }

    /**
     * @notice Update the backend wallet (admin only)
     */
    function setBackendWallet(address _backendWallet) external onlyRole(DEFAULT_ADMIN_ROLE) {
        backendWallet = _backendWallet;
    }
}

